-- admin_accounts schema + full seed, rebuilt in the Automate/
-- Flight-emails101 Supabase project (bhgmghwhwoltbbzbooxg). Source is the
-- REAL account data from the boss-provided external project's
-- 'employeeaccount' table (wuymgnqpkgxxxghvgcbq) — 348 rows, fetched
-- 2026-07-10 using a service_role key (bypasses RLS; the anon key could
-- never see these rows, hence the earlier '0 rows' confusion).
--
-- password_hash is bcrypt of each person's REAL 'generated_password' from
-- that table (pattern: initials + a date, e.g. 'RRR20260626') — NOT a
-- made-up default. Tell each employee their actual password as given by
-- that field. is_active mirrors that table's real status ('active'/
-- 'inactive'), not a blanket true.
--
-- No role/department/team_name fields exist in the source. Role defaults
-- to 'agent' except Ashley Danille Sarabia (POTB2026-0364) and Kevin
-- Dizon Timbol (GDX2022-0004), promoted to super_admin per instruction.
-- department/team_name left null — a cross-reference attempt against the
-- HR 'employee' table by employee_code found 0 matches (the two systems
-- use entirely different, non-overlapping ID schemes).
-- 5 people have no employee_code (login via email only for them):
--   Lyka Regino Lingcopines (lykalingcopines.gladex@gmail.com)
--   Kimberly Peñaflorida Fernandez (kimberlyfernandez.gladex@gmail.com)
--   Erika Mae Policarpio Pulido (erikamaepulido.gladex@gmail.com)
--   Lyka Quibal Sardua (lykasardua.gladex@gmail.com)
--   Julie Anne Rose Tividad Reonal (julieannerosereonal.gladex@gmail.com)

create table if not exists public.admin_accounts (
  id uuid primary key default gen_random_uuid(),
  full_name text,
  email text,
  employee_code text unique,
  password_hash text not null,
  role text not null default 'agent',
  team_name text,
  department text,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  last_login timestamptz
);

alter table public.admin_accounts enable row level security;

drop policy if exists "Allow anon read access" on public.admin_accounts;
create policy "Allow anon read access"
  on public.admin_accounts
  for select
  to anon
  using (true);

drop policy if exists "Allow anon update is_active" on public.admin_accounts;
create policy "Allow anon update is_active"
  on public.admin_accounts
  for update
  to anon
  using (true)
  with check (true);

create or replace function public.admin_accounts_restrict_anon_update()
returns trigger as $$
begin
  if current_user = 'anon' and (
    new.full_name is distinct from old.full_name
    or new.email is distinct from old.email
    or new.employee_code is distinct from old.employee_code
    or new.password_hash is distinct from old.password_hash
    or new.role is distinct from old.role
    or new.team_name is distinct from old.team_name
    or new.department is distinct from old.department
  ) then
    raise exception 'Only is_active/last_login can be updated via the anon key';
  end if;
  return new;
end;
$$ language plpgsql security definer set search_path = public;

drop trigger if exists admin_accounts_restrict_anon_update_trg on public.admin_accounts;
create trigger admin_accounts_restrict_anon_update_trg
  before update on public.admin_accounts
  for each row
  execute function public.admin_accounts_restrict_anon_update();

